1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
14	
15	const basePremiumFor = (items: Item[]): number =>
16	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
17	
18	const quoteStep = ({ items }: Step) => {
19	  const basePremium = basePremiumFor(items);
20	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
21	  return { premium: Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE) };
22	};
23	
24	export const runScenario = (input: Scenario): unknown => ({
25	  results: input.steps.map(quoteStep),
26	});
